export enum AppState {
  IDLE,
  RECORDING,
  TYPING,
  ANALYZING_INTERPRETATION,
  AWAITING_CONTEXT,
  ANALYZING_VISUAL,
  COMPLETE,
}

export interface DreamAnalysisData {
  imageUrl: string;
  interpretation: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface DreamContext {
  emotion: string;
  wakingFeeling: string;
  conclusion: string;
  personDescription: string;
  additionalInfo: string;
}

import React, { useState, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveSession, LiveServerMessage, Modality } from '@google/genai';
import { AppState, DreamAnalysisData, DreamContext } from './types';
import * as geminiService from './services/geminiService';
import { createBlob } from './utils/audio';
import Recorder from './components/Recorder';
import DreamAnalysis from './components/DreamAnalysis';
import ContextForm from './components/ContextForm';
import LoadingSpinner from './components/LoadingSpinner';

const App: React.FC = () => {
    const [appState, setAppState] = useState<AppState>(AppState.IDLE);
    const [transcription, setTranscription] = useState('');
    const [typedDream, setTypedDream] = useState('');
    const [finalDreamText, setFinalDreamText] = useState('');
    const [analysisResult, setAnalysisResult] = useState<DreamAnalysisData | null>(null);
    const [interpretation, setInterpretation] = useState<string | null>(null);
    const [dreamContext, setDreamContext] = useState<DreamContext | null>(null);
    const [loadingMessage, setLoadingMessage] = useState('');
    const [error, setError] = useState<string | null>(null);

    const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
    const audioContextRef = useRef<AudioContext | null>(null);
    const audioStreamRef = useRef<MediaStream | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);

    const cleanupAudio = useCallback(() => {
        audioStreamRef.current?.getTracks().forEach(track => track.stop());
        scriptProcessorRef.current?.disconnect();
        sourceNodeRef.current?.disconnect();
        audioContextRef.current?.close();

        audioStreamRef.current = null;
        scriptProcessorRef.current = null;
        sourceNodeRef.current = null;
        audioContextRef.current = null;
    }, []);

    const handleStartRecording = async () => {
        setError(null);
        setTranscription('');
        setAppState(AppState.RECORDING);

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            audioStreamRef.current = stream;
            audioContextRef.current = new ((window as any).AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
            sessionPromiseRef.current = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                callbacks: {
                    onopen: () => {
                        sourceNodeRef.current = audioContextRef.current!.createMediaStreamSource(stream);
                        scriptProcessorRef.current = audioContextRef.current!.createScriptProcessor(4096, 1, 1);

                        scriptProcessorRef.current.onaudioprocess = (audioProcessingEvent) => {
                            const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                            const pcmBlob = createBlob(inputData);
                            sessionPromiseRef.current?.then((session) => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };

                        sourceNodeRef.current.connect(scriptProcessorRef.current);
                        scriptProcessorRef.current.connect(audioContextRef.current.destination);
                    },
                    onmessage: (message: LiveServerMessage) => {
                        if (message.serverContent?.inputTranscription) {
                            const text = message.serverContent.inputTranscription.text;
                            setTranscription(prev => prev + text);
                        }
                    },
                    onerror: (e: ErrorEvent) => {
                        console.error('Live API Error:', e);
                        setError('A connection error occurred. Please try again.');
                        handleStopRecording(true);
                    },
                    onclose: () => {
                        cleanupAudio();
                    },
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                },
            });
        } catch (err) {
            console.error('Error starting recording:', err);
            setError('Could not access microphone. Please check permissions and try again.');
            setAppState(AppState.IDLE);
        }
    };

    const handleStopRecording = async (isError = false) => {
        sessionPromiseRef.current?.then(session => session.close());
        cleanupAudio();

        if (isError) {
            setAppState(AppState.IDLE);
            return;
        }

        if (transcription.trim().length < 10) {
            setError("Dream recording is too short. Please try again and describe your dream in more detail.");
            setAppState(AppState.IDLE);
            return;
        }

        startAnalysis(transcription);
    };

    const handleTypedSubmit = () => {
        if (typedDream.trim().length < 20) {
            setError("Please provide a bit more detail about your dream (at least 20 characters).");
            return;
        }
        startAnalysis(typedDream);
    };

    const startAnalysis = async (dreamText: string) => {
        setFinalDreamText(dreamText);
        setAppState(AppState.ANALYZING_INTERPRETATION);
        setError(null);

        try {
            setLoadingMessage('Weaving the threads of your subconscious...');
            const interpretationResult = await geminiService.analyzeDream(dreamText);
            setInterpretation(interpretationResult);
            setAppState(AppState.AWAITING_CONTEXT);
        } catch (err) {
            console.error('Interpretation error:', err);
            setError('There was an issue interpreting your dream. Please try again.');
            setAppState(AppState.IDLE);
        } finally {
            setLoadingMessage('');
        }
    };

    const handleContextSubmit = async (context: DreamContext) => {
        setDreamContext(context);
        setAppState(AppState.ANALYZING_VISUAL);

        try {
            setLoadingMessage("Crafting your dream's tapestry...");
            const imageUrl = await geminiService.generateDreamImage(finalDreamText, context);

            setAnalysisResult({ imageUrl, interpretation: interpretation! });
            setAppState(AppState.COMPLETE);
        } catch (err) {
            console.error('Image generation error:', err);
            setError('There was an issue generating the dream image. Please try again.');
            setAppState(AppState.IDLE);
        } finally {
            setLoadingMessage('');
        }
    };

    const handleReset = () => {
        setAppState(AppState.IDLE);
        setTranscription('');
        setTypedDream('');
        setFinalDreamText('');
        setAnalysisResult(null);
        setInterpretation(null);
        setDreamContext(null);
        setError(null);
    };

    const renderContent = () => {
        switch (appState) {
            case AppState.RECORDING:
                return <Recorder isRecording={true} transcription={transcription} onStopRecording={() => handleStopRecording(false)} />;
            case AppState.TYPING:
                return (
                    <div className="flex flex-col items-center justify-center p-8 h-full min-h-screen animate-fade-in w-full max-w-3xl mx-auto">
                        <h2 className="text-4xl font-bold text-light-text mb-6 font-display">Write Your Dream</h2>
                        <textarea
                            value={typedDream}
                            onChange={(e) => setTypedDream(e.target.value)}
                            placeholder="I was floating above a city made of bioluminescent coral..."
                            className="w-full h-64 bg-light-bg/50 backdrop-blur-md text-light-text p-6 rounded-2xl border-2 border-slate-700 focus:border-dreamy-purple focus:ring-2 focus:ring-dreamy-purple/20 outline-none transition-all text-lg leading-relaxed shadow-xl"
                        />
                        {error && <p className="text-red-400 mt-4 text-center">{error}</p>}
                        <div className="flex gap-4 mt-8">
                             <button
                                onClick={() => setAppState(AppState.IDLE)}
                                className="bg-slate-700 hover:bg-slate-600 text-light-text font-bold py-3 px-8 rounded-full transition-all"
                            >
                                Back
                            </button>
                            <button
                                onClick={handleTypedSubmit}
                                className="bg-dreamy-purple hover:bg-dreamy-indigo text-white font-bold py-3 px-10 rounded-full transition-all transform hover:scale-105 shadow-lg shadow-purple-500/30 text-lg"
                            >
                                Analyze Dream
                            </button>
                        </div>
                    </div>
                );
            case AppState.ANALYZING_INTERPRETATION:
            case AppState.ANALYZING_VISUAL:
                return <LoadingSpinner loadingMessage={loadingMessage} />;
            case AppState.AWAITING_CONTEXT:
                return interpretation && <ContextForm interpretation={interpretation} onSubmit={handleContextSubmit} />;
            case AppState.COMPLETE:
                return analysisResult && <DreamAnalysis analysis={analysisResult} dreamText={finalDreamText} context={dreamContext} onReset={handleReset}/>;
            case AppState.IDLE:
            default:
                return (
                    <div className="flex flex-col items-center justify-center text-center p-8 h-full min-h-screen">
                        <div className="flex-grow flex flex-col items-center justify-center">
                            <img src="/assets/logo.svg" alt="Dreamweavr AI Logo" className="w-20 h-20 mb-6" />
                            <h1 className="text-6xl md:text-7xl font-bold text-light-text mb-4 font-display">Dreamweavr AI</h1>
                            <p className="text-lg text-medium-text max-w-xl mb-10">Capture the logic of the night before it fades.</p>
                            {error && <p className="bg-red-900/50 border border-red-500 text-red-200 p-4 rounded-lg mb-6 max-w-xl">{error}</p>}
                            <div className="flex flex-col md:flex-row gap-6">
                                <button
                                    onClick={handleStartRecording}
                                    className="flex items-center gap-3 bg-dreamy-purple hover:bg-dreamy-indigo text-white font-bold py-4 px-10 rounded-full transition-all duration-300 transform hover:scale-105 shadow-lg shadow-purple-500/30 text-lg"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6"><path d="M8.25 4.5a3.75 3.75 0 1 1 7.5 0v8.25a3.75 3.75 0 1 1-7.5 0V4.5Z" /><path d="M6 10.5a.75.75 0 0 1 .75.75v1.5a5.25 5.25 0 1 0 10.5 0v-1.5a.75.75 0 0 1 1.5 0v1.5a6.75 6.75 0 1 1-13.5 0v-1.5A.75.75 0 0 1 6 10.5Z" /></svg>
                                    Record Dream
                                </button>
                                <button
                                    onClick={() => setAppState(AppState.TYPING)}
                                    className="flex items-center gap-3 bg-slate-800 hover:bg-slate-700 text-white font-bold py-4 px-10 rounded-full transition-all duration-300 transform hover:scale-105 border border-slate-600 text-lg"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6"><path d="M21.731 2.269a2.625 2.625 0 0 0-3.712 0l-1.157 1.157 3.712 3.712 1.157-1.157a2.625 2.625 0 0 0 0-3.712ZM19.513 8.199l-3.712-3.712-12.15 12.15a5.25 5.25 0 0 0-1.32 2.214l-.8 2.685a.75.75 0 0 0 .933.933l2.685-.8a5.25 5.25 0 0 0 2.214-1.32L19.513 8.199Z" /></svg>
                                    Type Dream
                                </button>
                            </div>
                        </div>
                        <footer className="w-full text-center text-medium-text py-6">
                            <p className="text-sm italic mb-2">Your privacy is paramount. We do not save your dream recordings or analyses.</p>
                            <p className="text-sm">Follow the journey with <span className="font-semibold text-dreamy-purple">#DreamweavrAI</span></p>
                        </footer>
                    </div>
                );
        }
    };

    return (
        <main className="bg-gradient-to-br from-dark-bg via-indigo-950 to-black min-h-screen w-full flex items-center justify-center">
            <style>{`
              @keyframes fade-in {
                from { opacity: 0; transform: translateY(10px); }
                to { opacity: 1; transform: translateY(0); }
              }
              .animate-fade-in { animation: fade-in 0.5s ease-out forwards; }
            `}</style>
            <div className="w-full h-full min-h-screen">
                {renderContent()}
            </div>
        </main>
    );
};

export default App;
